type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: unknown; steps: QuoteStep[] };

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};
const PROCESSING_FEE = 5;

export const runScenario = (input: Scenario): { results: { premium: number }[] } => {
  const results = input.steps.map((step) => {
    const base = BASE_PREMIUM[step.items[0].type];
    const withFirstInsurance = Math.ceil((base * 11) / 10);
    const premium = withFirstInsurance + PROCESSING_FEE;
    return { premium };
  });
  return { results };
};

