import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote — base premiums per item type", () => {
    it("quotes a sword for a brand-new customer: 100 base × 1.10 first-insurance + 5 fee = 115 G", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: false },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 115 }] });
    });
    it("quotes an amulet for a brand-new customer: 60 × 1.10 + 5 = 71 G", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [
              { type: "amulet", material: "silver", enchantment: 2, cursed: false },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 71 }] });
    });
    it("quotes a staff for a brand-new customer: 80 × 1.10 + 5 = 93 G", () => {
      const result = runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [
              { type: "staff", material: "oak", enchantment: 1, cursed: false },
            ],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 93 }] });
    });
    it.todo("quotes a potion for a brand-new customer: 40 × 1.10 + 5 = 49 G");
  });

  describe("Quote — components", () => {
    it.todo("quotes a single rune component at 25 base × 1.10 + 5, rounded up in MHPCO's favor = 33 G");
    it.todo("bundles 3 alike components at a special 60 G base instead of 75 G");
  });

  describe("Quote — surcharges and discounts", () => {
    it.todo("applies 50% cursed surcharge");
    it.todo("applies 30% high-enchantment surcharge (enchantment ≥ 5)");
    it.todo("applies 20% loyalty discount for customers with ≥ 2 years");
    it.todo("applies 15% discount on each contract after the first");
    it.todo("does not apply the first-insurance surcharge to contracts after the first");
  });

  describe("Claim — payouts", () => {
    it.todo("pays out damage minus 100 G deductible and reports remainingCap");
    it.todo("caps total payout per policy at twice the insurance sum across multiple claims");
    it.todo("reimburses 50% of damage for items with enchantment ≥ 8");
    it.todo("fully reimburses damage to dragon-material items");
  });
});

