const COMPONENT_BASE_PREMIUM = 25;
const BUNDLE_BASE_PREMIUM = 60;

const itemsBasePremium = (items: Item[]): number => {
  const firstType = items[0].type;
  const allAlike = items.every((item) => item.type === firstType);
  const isComponentBundle =
    items.length === 3 && allAlike && BASE_PREMIUM[firstType] === COMPONENT_BASE_PREMIUM;
  if (isComponentBundle) return BUNDLE_BASE_PREMIUM;
  return items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
};

export const runScenario = (input: Scenario): { results: { premium: number }[] } => {
  const results = input.steps.map((step) => {
    const base = itemsBasePremium(step.items);
    const withFirstInsurance = Math.ceil((base * 11) / 10);
    const premium = withFirstInsurance + PROCESSING_FEE;
    return { premium };
  });
  return { results };
};

